    @app.get("/webhooks/messaging/{integration_id}")
    async def messaging_webhook_verify(
        request: Request,
        integration_id: int,
        session: Session = Depends(get_db_session),
    ) -> PlainTextResponse:
        integration = session.execute(select(Integration).where(Integration.id == integration_id)).scalar_one_or_none()
        if integration is None or integration.status != "active":
            raise HTTPException(status_code=status.HTTP_404_NOT_FOUND, detail="Messaging integration not found.")
        if integration.provider_kind != "messaging" or integration.provider_name != "whatsapp":
            raise HTTPException(status_code=status.HTTP_405_METHOD_NOT_ALLOWED, detail="GET webhook verification is only available for WhatsApp.")
        mode = str(request.query_params.get("hub.mode") or "").strip()
        verify_token = str(request.query_params.get("hub.verify_token") or "").strip()
        challenge = str(request.query_params.get("hub.challenge") or "").strip()
        credentials = _load_integration_credentials(session, integration)
        expected_token = str(credentials.get("verify_token") or "").strip()
        if mode != "subscribe" or not challenge:
            raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail="Invalid webhook verification payload.")
        if not expected_token or not secrets.compare_digest(verify_token, expected_token):
            _log_integration_event(
                session,
                integration,
                level="error",
                event_type="webhook.verify_failed",
                status_code="forbidden",
                message="WhatsApp webhook verify token mismatch.",
                payload={"mode": mode},
                request_id=request.headers.get("x-request-id"),
            )
            raise HTTPException(status_code=status.HTTP_403_FORBIDDEN, detail="Webhook verify token mismatch.")
        integration.webhook_url = str(request.url.replace(query=""))
        integration.last_webhook_at = datetime.now(timezone.utc)
        _log_integration_event(
            session,
            integration,
            level="info",
            event_type="webhook.verified",
            status_code="ok",
            message="WhatsApp webhook verification completed.",
            payload={"mode": mode},
            request_id=request.headers.get("x-request-id"),
        )
        return PlainTextResponse(challenge)

    @app.post("/webhooks/messaging/{integration_id}")
    async def messaging_webhook_ingest(
        request: Request,
        integration_id: int,
        session: Session = Depends(get_db_session),
    ) -> JSONResponse:
        integration = session.execute(select(Integration).where(Integration.id == integration_id)).scalar_one_or_none()
        if integration is None or integration.status != "active":
            raise HTTPException(status_code=status.HTTP_404_NOT_FOUND, detail="Messaging integration not found.")
        if integration.provider_kind != "messaging":
            raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail="Integration is not a messaging provider.")
        registry = build_provider_registry()
        adapter = registry.get(integration.provider_kind, integration.provider_name)
        if adapter is None:
            raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail="Messaging provider adapter is not available.")
        body = await request.body()
        credentials = _load_integration_credentials(session, integration)
        allowed, auth_message, auth_payload = _verify_messaging_webhook(
            integration=integration,
            credentials=credentials,
            headers=dict(request.headers),
            body=body,
        )
        if not allowed:
            _log_integration_event(
                session,
                integration,
                level="error",
                event_type="webhook.auth_failed",
                status_code="forbidden",
                message=auth_message,
                payload=auth_payload,
                request_id=request.headers.get("x-request-id"),
            )
            raise HTTPException(status_code=status.HTTP_403_FORBIDDEN, detail=auth_message)
        try:
            records = adapter.receive_webhook(dict(request.headers), body)  # type: ignore[attr-defined]
        except Exception as exc:
            _log_integration_event(
                session,
                integration,
                level="error",
                event_type="webhook.parse_failed",
                status_code="bad_request",
                message=f"Webhook parsing failed: {exc}",
                payload=auth_payload,
                request_id=request.headers.get("x-request-id"),
            )
            raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail=f"Webhook parsing failed: {exc}") from exc
        context = TenantContext(
            account_id=integration.account_id,
            actor_user_id=None,
            source=f"{integration.provider_name}-webhook",
            request_id=request.headers.get("x-request-id"),
            is_system=True,
        )
        integration.last_webhook_at = datetime.now(timezone.utc)
        if integration.webhook_url is None:
            integration.webhook_url = str(request.url)
        batch, reviews = CommunicationService(session).import_inbound_messages(
            context,
            created_by_user_id=None,
            source_kind=f"{integration.provider_name}_webhook",
            batch_ref=f"{integration.external_ref or integration.id}:{datetime.now(timezone.utc).strftime('%Y%m%d%H%M%S')}",
            records=records,
        )
        settings_payload = integration.settings_json if isinstance(integration.settings_json, dict) else {}
        auto_create_tasks = bool(settings_payload.get("auto_create_tasks", True))
        created_tasks = 0
        if auto_create_tasks:
            account = session.execute(select(Account).where(Account.id == integration.account_id)).scalar_one()
            default_operator_id = None
            if isinstance(account.settings_json, dict) and account.settings_json.get("default_operator_user_id"):
                default_operator_id = int(account.settings_json["default_operator_user_id"])
            for review in reviews:
                if review.quality_status != "critical":
                    continue
                CommunicationService(session).create_follow_up_task(
                    context,
                    review_id=review.id,
                    created_by_user_id=None,
                    assignee_user_id=default_operator_id,
                    assignee_employee_id=review.employee_id,
                    due_at=None,
                )
                created_tasks += 1
        _log_integration_event(
            session,
            integration,
            level="info",
            event_type="webhook.ingested",
            status_code="ok",
            message=f"Ingested {len(records)} inbound messages from webhook.",
            payload={
                **auth_payload,
                "records_count": len(records),
                "reviews_count": len(reviews),
                "tasks_count": created_tasks,
            },
            request_id=request.headers.get("x-request-id"),
        )
        AuditLogService(session).log(
            context,
            "communications.webhook.ingested",
            "communication_import_batch",
            str(batch.id),
            details={
                "integration_id": integration.id,
                "provider_name": integration.provider_name,
                "records": len(records),
                "critical_count": batch.critical_count,
                "auto_tasks": created_tasks,
            },
        )
        return JSONResponse(
            {
                "integration_id": integration.id,
                "provider_name": integration.provider_name,
                "records_count": len(records),
                "batch": _serialize_communication_import_batch(batch),
                "reviews_count": len(reviews),
                "tasks_count": created_tasks,
            }
        )

    @app.post("/admin/{account_slug}/communications/reviews/{review_id}/task")
    async def admin_create_communication_task(
        request: Request,
        account_slug: str,
        review_id: int,
        session: Session = Depends(get_db_session),
    ) -> JSONResponse:
        await _require_csrf(request)
        payload = await request.json()
        actor = _require_admin_user(request, session)
        runtime = resolve_admin_runtime(request, session, account_slug=account_slug, actor_email=actor.email)
        ensure_permission(runtime, "tasks.manage")
        _ensure_account_feature(runtime, "communication_intelligence", "Communications")
        body = payload.get("task") or {}
        due_at_raw = str(body.get("due_at") or "").strip()
        due_at = datetime.fromisoformat(due_at_raw) if due_at_raw else None
        if due_at is not None and due_at.tzinfo is None:
            due_at = due_at.replace(tzinfo=timezone.utc)
        assignee_employee_id = int(body["assignee_employee_id"]) if body.get("assignee_employee_id") else None
        assignee_user_id = int(body["assignee_user_id"]) if body.get("assignee_user_id") else None
        try:
            if assignee_employee_id is not None and assignee_user_id is None:
                employee = PeopleService(session).get_employee(runtime.context, assignee_employee_id)
                assignee_user_id = employee.user_id
            task = CommunicationService(session).create_follow_up_task(
                runtime.context,
                review_id=review_id,
                created_by_user_id=runtime.actor_user.id,
                assignee_user_id=assignee_user_id,
                assignee_employee_id=assignee_employee_id,
                due_at=due_at,
            )
            AuditLogService(session).log(
                runtime.context,
                "communications.task.created",
                "task",
                str(task.id),
                details={"review_id": review_id, "assignee_employee_id": assignee_employee_id, "assignee_user_id": assignee_user_id},
            )
        except (PlatformCoreError, TenantContextError, ValueError) as exc:
            raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail=str(exc)) from exc
        return JSONResponse({"task": _serialize_task(task)})

    @app.get("/admin/{account_slug}/alerts-tasks", response_class=HTMLResponse)
    def admin_alerts_tasks(
        request: Request,
        account_slug: str,
        severity: str | None = Query(default=None),
        priority: str | None = Query(default=None),
        alert_code: str | None = Query(default=None),
        overdue: bool = Query(default=False),
        session: Session = Depends(get_db_session),
    ) -> HTMLResponse:
        user = _current_session_user(session, request)
        if user is None:
            request.session.clear()
            return _login_redirect(f"/admin/{account_slug}/alerts-tasks")
        actor_email = user.email
        runtime = resolve_admin_runtime(request, session, account_slug=account_slug, actor_email=actor_email)
        request.session["admin_account_slug"] = runtime.account.slug
        ensure_permission(runtime, "alerts.read")
        ensure_permission(runtime, "tasks.read")
        automation = RuntimeAutomationService(session)
        alerts = [item for item in automation.list_alerts(runtime.context) if item.status == "open"]
        tasks = [item for item in automation.list_tasks(runtime.context) if item.status == "open"]
        if severity:
            alerts = [item for item in alerts if item.severity == severity]
        if alert_code:
            alerts = [item for item in alerts if item.code == alert_code]
        if priority:
            tasks = [item for item in tasks if item.priority == priority]
        if overdue:
            tasks = [
                item for item in tasks
                if item.due_at is not None and item.due_at <= datetime.now(timezone.utc)
            ]
        user_ids = {item.assigned_user_id for item in alerts if item.assigned_user_id is not None}
        user_ids.update(item.assignee_user_id for item in tasks if item.assignee_user_id is not None)
        employee_ids = {item.assignee_employee_id for item in tasks if item.assignee_employee_id is not None}
        users = {
            item.id: item
            for item in session.execute(select(User).where(User.id.in_(user_ids))).scalars().all()
        } if user_ids else {}
        employees = {
            item.id: item
            for item in session.execute(select(Employee).where(Employee.id.in_(employee_ids))).scalars().all()
        } if employee_ids else {}
        overdue_tasks = [item for item in tasks if item.due_at is not None and item.due_at <= datetime.now(timezone.utc)]
        return templates.TemplateResponse(
            request,
            "admin/alerts_tasks.html",
            {
                **_admin_context(request, session, runtime, page="alerts_tasks"),
                "alerts": alerts,
                "tasks": tasks,
                "overdue_tasks": overdue_tasks,
                "severity_filter": severity,
                "priority_filter": priority,
                "alert_code_filter": alert_code,
                "overdue_filter": overdue,
                "users": users,
                "employees": employees,
                "alert_slas": _alert_sla_map(),
                "default_users": _default_account_users(runtime, session),
                "can_assign_defaults": _is_manager_role(runtime.role_code),
            },
        )

    @app.post("/admin/{account_slug}/alerts/{alert_id}/status")
    async def admin_alert_status(
        request: Request,
        account_slug: str,
        alert_id: int,
        session: Session = Depends(get_db_session),
    ) -> JSONResponse:
        await _require_csrf(request)
